/* ── INIT ─────────────────────────────────────────────────── */
document.addEventListener('DOMContentLoaded',function(){
  // Handle hash-based routing on initial load
  var hash=(window.location.hash||'').replace('#','');
  var validPages=['home','therapies','gallery','membership','about','contact','more'];
  var startPage=validPages.indexOf(hash)>=0?hash:'home';
  // Set initial page without triggering history push
  document.querySelectorAll('.page').forEach(function(p){p.classList.remove('active');});
  var startEl=document.getElementById('page-'+startPage);
  if(startEl) startEl.classList.add('active');
  document.querySelectorAll('.nl').forEach(function(a){
    a.classList.toggle('active',a.getAttribute('data-page')===startPage);
  });

  detectLang();
  initHero();
  initTop3VideoHover();
  renderTherapyCards();
  renderGallery();
  renderLegal();
  initOffer();
  initScrollEffects();
  var fd=document.getElementById('fDate');
  if(fd) fd.min=new Date().toISOString().split('T')[0];
  document.querySelectorAll('.modal-overlay').forEach(function(m){
    m.addEventListener('click',function(e){
      if(e.target===m){m.classList.remove('show');document.body.style.overflow='';}
    });
  });
});

/* ── LANGUAGE ─────────────────────────────────────────────── */
function detectLang(){
  const s=localStorage.getItem('mauliLang')||'hi';
  setLang(s);
}
function t(key){
  const lang=T[currentLang]||T[FALLBACK_LANG];
  return lang[key]||(T[FALLBACK_LANG]&&T[FALLBACK_LANG][key])||key;
}
function applyTranslations(){
  document.querySelectorAll('[data-i18n]').forEach(el=>{
    const k=el.getAttribute('data-i18n');
    const val=t(k);
    if(val&&val!==k) el.innerHTML=val;
  });
}
function setLang(lang){
  currentLang=lang;
  localStorage.setItem('mauliLang',lang);
  const lbl=document.getElementById('langLabel');
  if(lbl) lbl.textContent=LANG_LABELS[lang]||lang.toUpperCase();
  document.documentElement.lang=lang;
  applyTranslations();
  closeLangMenu();
  renderTherapyCards();
}
function toggleLangMenu(){
  var m=document.getElementById('langMenu');
  if(m) m.classList.toggle('open');
}
function closeLangMenu(){
  var m=document.getElementById('langMenu');
  if(m) m.classList.remove('open');
}
document.addEventListener('click',function(e){
  if(!e.target.closest('#langWrap')) closeLangMenu();
});

/* ── VISIT COUNTER ────────────────────────────────────────── */
function initVisitCounter(){
  let c=parseInt(localStorage.getItem('mauliVisits')||'0')+1;
  localStorage.setItem('mauliVisits',c);
  const base=13241+c;
  const el=document.getElementById('visitCount');
  animCount(el,base);
}
function animCount(el,target){
  if(!el) return;
  let n=target-60;
  const step=Math.ceil((target-n)/50);
  const tmr=setInterval(()=>{
    n=Math.min(n+step,target);
    el.textContent=n.toLocaleString('en-IN');
    if(n>=target) clearInterval(tmr);
  },25);
}

/* ── HERO VIDEO — 6 videos, full HD, auto-rotate ─────────── */
function initHero(){
  const videos=Array.from(document.querySelectorAll('.hero-video'));
  const bar=document.getElementById('heroBar');
  if(!videos.length) return;

  // Preload next video before switching
  function preloadNext(){
    const next=(currentHeroIdx+1)%videos.length;
    videos[next].preload='auto';
    try{ videos[next].load(); }catch(e){}
  }

  function showVideo(idx){
    videos.forEach((v,i)=>{
      v.classList.toggle('active',i===idx);
      if(i===idx){ try{v.play();}catch(e){} }
    });
    if(bar){ bar.style.width='0'; setTimeout(()=>bar.style.width='100%',60); }
  }

  function nextVideo(){
    currentHeroIdx=(currentHeroIdx+1)%videos.length;
    showVideo(currentHeroIdx);
    preloadNext();
  }

  // Start first video
  showVideo(0);
  preloadNext();
  if(bar){ bar.style.transition='width 6s linear'; setTimeout(()=>bar.style.width='100%',120); }
  if(heroTimer) clearInterval(heroTimer);
  heroTimer=setInterval(nextVideo,6000);
}

/* ── TOP3 CARD STROKE VIDEO — play on hover of each card ─── */
function initTop3VideoHover(){
  document.querySelectorAll('.top3-card-hover').forEach(card=>{
    const vid=card.querySelector('.top3-stroke-video');
    if(!vid) return;
    card.addEventListener('mouseenter',()=>{
      vid.preload='auto';
      try{ vid.play(); }catch(e){}
    });
    card.addEventListener('mouseleave',()=>{
      try{ vid.pause(); vid.currentTime=0; }catch(e){}
    });
    // Touch support
    card.addEventListener('touchstart',()=>{
      vid.preload='auto';
      try{ vid.play(); }catch(e){}
    },{passive:true});
  });
}

/* ── NAV ──────────────────────────────────────────────────── */
function navTo(page){
  if(page==='terms'){openLegalPopup('terms');return;}
  if(page==='privacy'){openLegalPopup('privacy');return;}
  // Hide all pages
  document.querySelectorAll('.page').forEach(function(p){p.classList.remove('active');});
  // Show requested page
  var el=document.getElementById('page-'+page);
  if(el){el.classList.add('active');}else{
    // fallback: show home
    var home=document.getElementById('page-home');
    if(home) home.classList.add('active');
    page='home';
  }
  // Scroll to top
  try{window.scrollTo({top:0,behavior:'smooth'});}catch(e){window.scrollTo(0,0);}
  // Update hash for GitHub Pages deep linking
  if(history.pushState){
    history.pushState(null,null,'#'+page);
  } else {
    window.location.hash='#'+page;
  }
  // Close mobile nav
  var nav=document.getElementById('mainNav');
  var hb=document.getElementById('hamburger');
  if(nav) nav.classList.remove('mobile-open');
  if(hb) hb.classList.remove('open');
  // Update active nav link
  document.querySelectorAll('.nl').forEach(function(a){
    a.classList.toggle('active',a.getAttribute('data-page')===page);
  });
}
// Handle browser back/forward
window.addEventListener('popstate',function(){
  var hash=(window.location.hash||'#home').replace('#','');
  var validPages=['home','therapies','gallery','membership','about','contact','more'];
  navTo(validPages.indexOf(hash)>=0?hash:'home');
});
function setNavActive(el){
  document.querySelectorAll('.nl').forEach(a=>a.classList.remove('active'));
  if(el) el.classList.add('active');
}
function toggleMobileNav(){
  var nav=document.getElementById('mainNav');
  var hb=document.getElementById('hamburger');
  if(nav) nav.classList.toggle('mobile-open');
  if(hb) hb.classList.toggle('open');
}

/* ── LEGAL POPUP ──────────────────────────────────────────── */
function openLegalPopup(type){
  const content=document.getElementById('legalPopupContent');
  if(!content) return;
  const title=type==='terms'?t('termsH1'):t('privacyH1');
  const body=type==='terms'?TERMS_CONTENT:PRIVACY_CONTENT;
  content.innerHTML=`<h2 style="font-family:var(--fd);color:var(--green);margin-bottom:16px">${title}</h2><p style="font-size:.82rem;color:#888;margin-bottom:24px;font-style:italic;">${t('legalUpdated')}</p><div class="legal-page">${body}</div>`;
  const modal=document.getElementById('legalPopupModal');
  if(modal){modal.classList.add('show');document.body.style.overflow='hidden';}
}

/* ── OFFER POPUP ──────────────────────────────────────────── */
function initOffer(){
  if(sessionStorage.getItem('mauliOffer')) return;
  setTimeout(()=>{
    document.getElementById('offerPopup')?.classList.add('show');
    document.getElementById('offerBackdrop')?.classList.add('show');
  },1200);
  setTimeout(()=>closeOffer(),7200);
  document.getElementById('offerPopup')?.addEventListener('click',e=>{
    if(!e.target.closest('#offerCloseBtn')){closeOffer();navTo('therapies');}
  });
  document.getElementById('offerBackdrop')?.addEventListener('click',closeOffer);
  document.getElementById('offerCloseBtn')?.addEventListener('click',closeOffer);
}
function closeOffer(){
  document.getElementById('offerPopup')?.classList.remove('show');
  document.getElementById('offerBackdrop')?.classList.remove('show');
  sessionStorage.setItem('mauliOffer','1');
}

/* ── SCROLL EFFECTS ───────────────────────────────────────── */
function initScrollEffects(){
  const header=document.getElementById('mainHeader');
  const btt=document.getElementById('backToTop');
  window.addEventListener('scroll',()=>{
    const s=window.scrollY;
    if(header) header.classList.toggle('scrolled',s>60);
    if(btt) btt.classList.toggle('show',s>350);
  },{passive:true});
  const io=new IntersectionObserver(entries=>{
    entries.forEach(e=>{
      if(e.isIntersecting){
        e.target.style.opacity='1';
        e.target.style.transform='translateY(0)';
        io.unobserve(e.target);
      }
    });
  },{threshold:.1,rootMargin:'0px 0px -40px 0px'});
  document.querySelectorAll('.why-card,.benefit-card,.review-card,.plan-card,.more-feature-card,.mq-card').forEach((el,i)=>{
    el.style.opacity='0';
    el.style.transform='translateY(28px)';
    el.style.transition=`opacity .5s ${i*.07}s ease,transform .5s ${i*.07}s ease`;
    io.observe(el);
  });
}

/* ── THERAPY CARDS (stroke video on hover + 6-image carousel + multilingual) ── */
function renderTherapyCards(){
  const grid=document.getElementById('therapiesGrid');
  if(!grid) return;
  const seeMoreTxt=t('seeMore')||'See More';
  const bookNowTxt=t('bookNow')||'Book Now';
  grid.innerHTML=THERAPIES.map((th,i)=>{
    const name=getTherapyText(th.nameKey);
    const price=getTherapyText(th.priceKey);
    const dur=getTherapyText(th.durKey);
    const short=getTherapyText(th.shortKey);
    return `
    <div class="tc" tabindex="0" aria-label="${name}">
      <div class="tc-media">
        <img src="${th.imgs[0]}" alt="${name}" loading="lazy" class="tc-img">
        <video class="tc-stroke-video" muted loop playsinline preload="none">
          <source src="${th.videoSrc}" type="video/mp4">
        </video>
        <div class="tc-overlay-btn">
          <button class="tc-see-more" onclick="openTherapyModal(${i});event.stopPropagation()">
            <i class="fas fa-eye"></i> ${seeMoreTxt}
          </button>
        </div>
      </div>
      <div class="tc-body">
        <h3>${name}</h3>
        <p>${short}</p>
        <div class="tc-meta">
          <span class="tc-price">${price}</span>
          <span class="tc-dur"><i class="fas fa-clock"></i> ${dur}</span>
        </div>
        <div class="tc-btns">
          <button class="btn-gold btn-sm" onclick="navTo('contact')">${bookNowTxt}</button>
          <button class="btn-outline btn-sm" onclick="openTherapyModal(${i})">${seeMoreTxt}</button>
        </div>
      </div>
    </div>`;
  }).join('');

  grid.querySelectorAll('.tc').forEach((card,i)=>{
    card.addEventListener('mouseenter',()=>{
      const vid=card.querySelector('.tc-stroke-video');
      const img=card.querySelector('.tc-img');
      if(vid&&img){
        img.style.opacity='0';
        vid.style.opacity='1';
        vid.preload='auto';
        try{vid.play();}catch(e){}
      }
    });
    card.addEventListener('mouseleave',()=>{
      const vid=card.querySelector('.tc-stroke-video');
      const img=card.querySelector('.tc-img');
      if(vid&&img){
        img.style.opacity='1';
        vid.style.opacity='0';
        try{vid.pause();vid.currentTime=0;}catch(e){}
      }
    });
    card.addEventListener('keydown',e=>{if(e.key==='Enter') openTherapyModal(i);});
  });
}

/* ── THERAPY MODAL (6-image autoplay carousel) ────────────── */
function openTherapyModal(idx){
  const th=THERAPIES[idx];
  if(!th) return;
  tmCarouselIdx=0;
  const modal=document.getElementById('therapyModal');
  const content=document.getElementById('therapyModalContent');
  if(!modal||!content) return;
  const name=getTherapyText(th.nameKey);
  const price=getTherapyText(th.priceKey);
  const dur=getTherapyText(th.durKey);
  const long=getTherapyText(th.longKey);
  const phys=th.physKeys.map(k=>getTherapyText(k));
  const ment=th.mentKeys.map(k=>getTherapyText(k));
  const forWhom=getTherapyText(th.forWhomKey);
  const physLabel=currentLang==='hi'?'शारीरिक लाभ':currentLang==='mr'?'शारीरिक फायदे':'Physical Benefits';
  const mentLabel=currentLang==='hi'?'मानसिक लाभ':currentLang==='mr'?'मानसिक फायदे':'Mental Benefits';
  const forLabel=currentLang==='hi'?'किसके लिए?':currentLang==='mr'?'कोणासाठी?':'Who is it for?';
  const bookLabel=`${t('bookNow')||'Book Now'} — ${price}`;
  const dotHtml=th.imgs.map((_,i)=>`<span class="tmc-dot${i===0?' active':''}" onclick="tmGoTo(${i})"></span>`).join('');
  content.innerHTML=`
    <div class="tm-name">${name}</div>
    <div class="tm-meta">
      <span class="tm-price">${price}</span>
      <span class="tm-dur"><i class="fas fa-clock"></i> ${dur}</span>
    </div>
    <div class="tm-carousel">
      <div class="tm-carousel-track" id="tmTrack">
        ${th.imgs.map(src=>`<div class="tm-slide"><img src="${src}" alt="${name}" loading="lazy"></div>`).join('')}
      </div>
      <button class="tm-carousel-prev" onclick="tmNav(-1)" aria-label="Previous"><i class="fas fa-chevron-left"></i></button>
      <button class="tm-carousel-next" onclick="tmNav(1)" aria-label="Next"><i class="fas fa-chevron-right"></i></button>
    </div>
    <div class="tm-carousel-dots" id="tmDots">${dotHtml}</div>
    <p class="tm-desc">${long}</p>
    <div class="tm-benefits">
      <h4>${physLabel}</h4>
      <ul>${phys.map(b=>`<li><i class="fas fa-check-circle"></i> ${b}</li>`).join('')}</ul>
      <h4>${mentLabel}</h4>
      <ul>${ment.map(b=>`<li><i class="fas fa-check-circle"></i> ${b}</li>`).join('')}</ul>
      <h4>${forLabel}</h4>
      <p class="for-whom">${forWhom}</p>
    </div>
    <button class="btn-gold btn-full" style="margin-top:20px" onclick="navTo('contact');closeTherapyModal()">${bookLabel}</button>
  `;
  tmCarouselEl=document.getElementById('tmTrack');
  tmCarouselDots=Array.from(document.querySelectorAll('.tmc-dot'));
  modal.classList.add('show');
  document.body.style.overflow='hidden';
  if(window._tmInterval) clearInterval(window._tmInterval);
  window._tmInterval=setInterval(()=>tmNav(1),2500);
}
function tmNav(dir){
  const len=6;
  tmCarouselIdx=(tmCarouselIdx+dir+len)%len;
  if(tmCarouselEl) tmCarouselEl.style.transform=`translateX(-${tmCarouselIdx*100}%)`;
  tmCarouselDots.forEach((d,i)=>d.classList.toggle('active',i===tmCarouselIdx));
}
function tmGoTo(i){
  tmCarouselIdx=i;
  if(tmCarouselEl) tmCarouselEl.style.transform=`translateX(-${i*100}%)`;
  tmCarouselDots.forEach((d,j)=>d.classList.toggle('active',j===i));
}
function closeTherapyModal(){
  var tm=document.getElementById('therapyModal');if(tm) tm.classList.remove('show');
  document.body.style.overflow='';
  if(window._tmInterval) clearInterval(window._tmInterval);
}

